import type { AnchorHTMLAttributes } from 'react';
export type StoreType = 'appstore' | 'googleplay' | 'appgallery';
export type StoreTheme = 'black' | 'white';
export type StoreLang = 'ru' | 'en';
export interface StoreProps extends AnchorHTMLAttributes<HTMLAnchorElement> {
    store: StoreType;
    theme: StoreTheme;
    lang: StoreLang;
    href: string;
    className?: string;
    dataTestId?: string;
    ariaLabel?: string;
}
